1	import type OpenAI from "openai";
2	import type {
3		ResponseFunctionToolCall,
4		ResponseInput,
5		ResponseInputContent,
6		ResponseInputImage,
7		ResponseInputText,
8		ResponseOutputItem,
9		ResponseOutputMessage,
10		ResponseReasoningItem,
11	} from "openai/resources/responses/responses";
12	import { calculateCost } from "../models";
13	import type {
14		Api,
15		AssistantMessage,
16		ImageContent,
17		Model,
18		StopReason,
19		TextContent,
20		TextSignatureV1,
21		ThinkingContent,
22		ToolCall,
23		ToolResultMessage,
24	} from "../types";
25	import { normalizeResponsesToolCallId } from "../utils";
26	import type { AssistantMessageEventStream } from "../utils/event-stream";
27	import { parseStreamingJson } from "../utils/json-parse";
28	
29	export function encodeTextSignatureV1(id: string, phase?: TextSignatureV1["phase"]): string {
30		const payload: TextSignatureV1 = { v: 1, id };
31		if (phase) payload.phase = phase;
32		return JSON.stringify(payload);
33	}
34	
35	export function parseTextSignature(
36		signature: string | undefined,
37	): { id: string; phase?: TextSignatureV1["phase"] } | undefined {
38		if (!signature) return undefined;
39		if (signature.startsWith("{")) {
40			try {
41				const parsed = JSON.parse(signature) as Partial<TextSignatureV1>;
42				if (parsed.v === 1 && typeof parsed.id === "string") {
43					if (parsed.phase === "commentary" || parsed.phase === "final_answer") {
44						return { id: parsed.id, phase: parsed.phase };
45					}
46					return { id: parsed.id };
47				}
48			} catch {
49				// Fall through to legacy plain-string handling.
50			}
51		}
52		return { id: signature };
53	}
54	
55	export function normalizeResponsesToolCallIdForTransform(id: string): string {
56		if (!id.includes("|")) return id;
57		const normalized = normalizeResponsesToolCallId(id);
58		return `${normalized.callId}|${normalized.itemId}`;
59	}
60	
61	export function collectKnownCallIds(messages: ResponseInput): Set<string> {
62		const knownCallIds = new Set<string>();
63		for (const item of messages) {
64			if (item.type === "function_call" && typeof item.call_id === "string") {
65				knownCallIds.add(item.call_id);
66			}
67		}
68		return knownCallIds;
69	}
70	
71	export function convertResponsesInputContent(
72		content: string | Array<TextContent | ImageContent>,
73		supportsImages: boolean,
74	): ResponseInputContent[] | undefined {
75		if (typeof content === "string") {
76			if (content.trim().length === 0) return undefined;
77			return [{ type: "input_text", text: content.toWellFormed() } satisfies ResponseInputText];
78		}
79	
80		const normalizedContent = content
81			.map((item): ResponseInputContent => {
82				if (item.type === "text") {
83					return {
84						type: "input_text",
85						text: item.text.toWellFormed(),
86					} satisfies ResponseInputText;
87				}
88				return {
89					type: "input_image",
90					detail: "auto",
91					image_url: `data:${item.mimeType};base64,${item.data}`,
92				} satisfies ResponseInputImage;
93			})
94			.filter(item => supportsImages || item.type !== "input_image")
95			.filter(item => item.type !== "input_text" || item.text.trim().length > 0);
96	
97		return normalizedContent.length > 0 ? normalizedContent : undefined;
98	}
99	
100	export function convertResponsesAssistantMessage<TApi extends Api>(
101		assistantMsg: AssistantMessage,
102		model: Model<TApi>,
103		msgIndex: number,
104		knownCallIds: Set<string>,
105	): ResponseInput {
106		const outputItems: ResponseInput = [];
107		const isDifferentModel =
108			assistantMsg.model !== model.id && assistantMsg.provider === model.provider && assistantMsg.api === model.api;
109	
110		for (const block of assistantMsg.content) {
111			if (block.type === "thinking" && assistantMsg.stopReason !== "error") {
112				if (block.thinkingSignature) {
113					outputItems.push(JSON.parse(block.thinkingSignature) as ResponseReasoningItem);
114				}
115				continue;
116			}
117	
118			if (block.type === "text") {
119				const parsedSignature = parseTextSignature(block.textSignature);
120				let msgId = parsedSignature?.id;
121				if (!msgId) {
122					msgId = `msg_${msgIndex}`;
123				} else if (msgId.length > 64) {
124					msgId = `msg_${Bun.hash.xxHash64(msgId).toString(36)}`;
125				}
126				outputItems.push({
127					type: "message",
128					role: "assistant",
129					content: [{ type: "output_text", text: block.text.toWellFormed(), annotations: [] }],
